   182	    private void handlePhyrexianManaCosts(Ability abilityToPay, Player payingPlayer, Ability source, Game game) {
   183	        if (this.isEmpty()) {
   184	            return; // nothing to be done without any mana costs. prevents NRE from occurring here
   185	        }
   186	        Iterator<T> manaCostIterator = this.iterator();
   187	        Costs<PayLifeCost> tempCosts = new CostsImpl<>();
   188	
   189	        while (manaCostIterator.hasNext()) {
   190	            ManaCost manaCost = manaCostIterator.next();
   191	            if (!manaCost.isPhyrexian()) {
   192	                continue;
   193	            }
   194	            PayLifeCost payLifeCost = new PayLifeCost(2);
   195	            if (payLifeCost.canPay(abilityToPay, source, payingPlayer.getId(), game)
   196	                    && payingPlayer.chooseUse(Outcome.LoseLife, "Pay 2 life instead of " + manaCost.getText().replace("/P", "") + '?', source, game)) {
   197	                manaCostIterator.remove();
   198	                tempCosts.add(payLifeCost);
   199	                this.incrPhyrexianPaid();
   200	            }
   201	        }
   202	
   203	        tempCosts.pay(source, game, source, payingPlayer.getId(), false, null);
   204	    }
